from flask import Flask, request, render_template, redirect, url_for, session, flash
import secrets
import hashlib
import time
from datetime import datetime, timedelta

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)

# Mock user database
users = {
    "admin": {
        "password": hashlib.sha256("password123".encode()).hexdigest(),
        "mfa_secret": "GHSYQ5Z7FV3N5N7T"
    }
}

# Mock MFA verification
def verify_mfa(user_id, code):
    # In a real app, this would verify against a TOTP generator
    # For demo, we'll accept any 6-digit code
    return len(code) == 6 and code.isdigit()

# Mock MFA token generator
def generate_mfa_token():
    return str(secrets.randbelow(1000000)).zfill(6)

@app.route('/')
def index():
    if 'user_id' in session:
        return f"Welcome {session['user_id']}! <a href='/logout'>Logout</a>"
    return "Welcome! <a href='/login'>Login</a>"

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        
        if username in users:
            stored_password = users[username]["password"]
            if hashlib.sha256(password.encode()).hexdigest() == stored_password:
                session['user_id'] = username
                session['mfa_verified'] = False
                session['mfa_token'] = generate_mfa_token()
                return redirect(url_for('verify_mfa'))
        
        flash("Invalid username or password")
        return redirect(url_for('login'))
    
    return render_template('login.html')

@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if 'user_id' not in session:
        return redirect(url_for('login'))
    
    if session.get('mfa_verified'):
        return redirect(url_for('protected'))
    
    if request.method == 'POST':
        code = request.form['code']
        if verify_mfa(session['user_id'], code):
            session['mfa_verified'] = True
            return redirect(url_for('protected'))
        else:
            flash("Invalid MFA code")
            return redirect(url_for('verify_mfa'))
    
    return render_template('verify_mfa.html', token=session['mfa_token'])

@app.route('/protected')
def protected():
    if 'user_id' not in session or not session.get('mfa_verified'):
        return redirect(url_for('login'))
    return f"Protected content for {session['user_id']}!"

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)